import { fn, type } from "arktype";

// Define the response shape type
const responseType = type({
  status: "integer >= 100 & <= 599",
  body: "string",
});

// Define fetchWithTimeout using ArkType's type.fn
// Parameters: url (URL string), timeoutMs (integer 1..10000), retries (integer 0..5)
// Return: Promise of { status: integer 100..599, body: string }
export const fetchWithTimeout = fn(
  {
    url: "string.url",
    timeoutMs: "integer > 0 & <= 10000",
    retries: "integer >= 0 & <= 5",
  },
  ":",
  responseType,
)(async (params) => {
  // Simulate a network call with setTimeout
  // Always resolve after min(timeoutMs, 50) milliseconds
  const delay = Math.min(params.timeoutMs, 50);
  await new Promise<void>((resolve) => setTimeout(resolve, delay));
  return { status: 200, body: "ok" };
});

import { fetchWithTimeout } from "./src/validator.ts";

async function main(): Promise<void> {
  // Read JSON from stdin
  const chunks: Buffer[] = [];
  for await (const chunk of process.stdin) {
    chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk));
  }
  const input = Buffer.concat(chunks).toString("utf-8").trim();

  let parsed: unknown;
  try {
    parsed = JSON.parse(input);
  } catch {
    process.stdout.write("ERR invalid JSON input\n");
    return;
  }

  // Extract params from the JSON document
  const doc = parsed as Record<string, unknown>;
  const params = doc.params;

  try {
    const result = await fetchWithTimeout(params);
    process.stdout.write(`OK ${JSON.stringify(result)}\n`);
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err);
    process.stdout.write(`ERR ${message}\n`);
  }
}

main();

